    "version": "2026-06-09.framework-neutral-component-factory",
    "source": "packages/ui/src/primitive-components.mjs",
    "implementationStatus": "framework-neutral-component-factory",
    "runtimeReactRenderer": false,
    "hostedRuntime": false,
    "harnessRuntimeExecution": false,
    "executableActions": false,
    "radixWrapper": false
  },
  "appShell": {
    "id": "app.solo.shell",
    "layout": "workspace-with-rail",
    "navigation": [
      {
        "label": "Today",
        "route": "/solo/today"
      },
      {
        "label": "Tasks",
        "route": "/solo/tasks"
      },
      {
        "label": "Docs",
        "route": "/solo/docs"
      },
      {
        "label": "Admin",
        "route": "/solo/admin"
      }
    ]
  },
  "routes": [
    {
      "path": "/solo/today",
      "page": "page.solo.today",
      "title": "Today command center",
      "blocks": [
        "block.solo.agenda",
        "block.solo.task-queue",
        "block.solo.agent-status"
      ]
    },
    {
      "path": "/solo/docs",
      "page": "page.solo.docs",
      "title": "Docs and sources",
      "blocks": [
        "block.solo.docs-sources",
        "block.solo.forms"
      ]
    }
  ],
  "pages": [
    {
      "id": "page.solo.today",
      "title": "Today command center",
      "routeCount": 1,
      "implementationFile": "studio-ui/workspaces/solo/pages/solo-today-page.page.implementation.json"
    },
    {
      "id": "page.solo.docs",
      "title": "Docs and sources",
      "routeCount": 1,
      "implementationFile": "studio-ui/workspaces/solo/pages/solo-docs-page.page.implementation.json"
    }
  ],
  "blocks": [
    {
      "id": "block.solo.agenda",
      "title": "Agenda",
      "component": "data-list",
      "implementationFile": "studio-ui/workspaces/solo/blocks/solo-agenda-block.block.implementation.json"
    },
    {
      "id": "block.solo.task-queue",
      "title": "Task queue",
      "component": "data-list",
      "implementationFile": "studio-ui/workspaces/solo/blocks/solo-task-queue-block.block.implementation.json"
    },
    {
      "id": "block.solo.agent-status",
      "title": "Agent status",
      "component": "agent-panel",
      "implementationFile": "studio-ui/workspaces/solo/blocks/solo-agent-status-block.block.implementation.json"
    },
    {
      "id": "block.solo.docs-sources",
      "title": "Docs sources",
      "component": "docs-source-panel",
      "implementationFile": "studio-ui/workspaces/solo/blocks/solo-docs-sources-block.block.implementation.json"
    },
    {
      "id": "block.solo.forms",
      "title": "Quick form",
      "component": "text-field",
      "implementationFile": "studio-ui/workspaces/solo/blocks/solo-forms-block.block.implementation.json"
    }
  ],
  "agentManifests": [
    {
      "component": "agent-panel",
      "manifestId": "agm_agent_panel",
      "manifestSchema": "https://jami.studio/schemas/registry/agent-manifest.schema.json",
      "schemaVersion": "2026-06-23.agent-manifest",
      "propContractVersion": "2026-06-09.ui-props",
      "actionSlots": [
        {
          "slotId": "slot_agent_panel_review",
          "name": "review",
          "label": "Review agent recommendation",
          "harnessRoute": "harness://actions/agent-panel-review",
          "risk": "write",
          "policyScope": "data:write",
          "confirmationMode": "approval_required",
          "inputSchema": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "recommendationId",
              "decision"
            ],
            "properties": {
              "recommendationId": {
                "type": "string"
              },
              "decision": {
                "type": "string",
                "enum": [
                  "approve",
                  "deny"
                ]
              }
            }
          },
          "outputSchema": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "status",
              "actionId",
              "policyDecision"
            ],
            "properties": {
              "status": {
                "type": "string",
                "enum": [
                  "accepted",
                  "denied"
                ]
              },
              "actionId": {
                "type": "string",
                "pattern": "^act_[a-z0-9][a-z0-9_-]*$"
              },
              "policyDecision": {
                "type": "string",
                "enum": [
                  "allow",
                  "deny",
                  "needs_approval",
                  "needs_owner"
                ]
              },
              "evidenceRef": {
                "type": "string",
                "pattern": "^ev_[a-z0-9][a-z0-9_-]*$"
              }
            }
          },
          "safetyConstraints": [
            "policy-required",
            "audit-required",
            "evidence-required",
            "no-inline-secret-values",
            "no-model-provided-code",
            "schema-validated-input",
            "schema-validated-output"
          ]
        }
      ],
      "bindingMode": "resident-component",
      "execution": "display-only-data-never-code"
    },
